SELECT skill_id
FROM skill_stats
WHERE usage_count > 10;

SELECT COUNT(*) AS completed_quests
FROM player_quests
WHERE player_id = 1 AND status = 'completed';

SELECT COUNT(cooldown_id) AS cooldown_count
FROM cooldowns
WHERE skill_id = 1;

SELECT skill_id
FROM cooldowns
WHERE cooldown_time IN ('1s', '2s');

SELECT skill_id
FROM skill_stats
WHERE usage_count = (SELECT MAX(usage_count) FROM skill_stats);
